// ============================================
// INPUT: Data from Airtable Webhook
// ============================================
const airtableItems = $input.all();

if (!airtableItems || airtableItems.length === 0) {
  return [{ json: { error: "No Airtable data received" } }];
}

// ============================================
// HELPER FUNCTIONS
// ============================================
function formatDate(dateString) {
  if (!dateString) return 'N/A';
  const date = new Date(dateString);
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  return `${months[date.getMonth()]} ${date.getDate()}, ${date.getFullYear()}`;
}

function formatSkillsTools(skillsToolsText) {
  if (!skillsToolsText) return 'N/A';
  return skillsToolsText.replace(/\n/g, '<br>');
}

// ============================================
// PDF FETCH + TEXT EXTRACTION HELPER
// ============================================

async function extractPdfTextFromUrl(url) {
  if (!url) return 'No resume link provided';
  try {
    const response = await fetch(url);
    const arrayBuffer = await response.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    // Requires pdf-parse installed in your n8n instance
    const pdf = require('pdf-parse');
    const data = await pdf(buffer);
    return data.text || 'No text found in PDF';
  } catch (err) {
    return `Error extracting PDF: ${err.message}`;
  }
}

// ============================================
// PROCESS EACH VA RECORD
// ============================================
const vaRecords = [];

for (const item of airtableItems) {
  const fields = item.json?.body?.fields || {};

  const resumeUrl = fields['Resume URL'] || fields['Updated Resume']?.[0]?.url || null;
  const extractedText = await extractPdfTextFromUrl(resumeUrl);

  vaRecords.push({
    name: fields['Virtual Assistants Name'] || 'N/A',
    btpId: fields['BTP ID'] || 'N/A',
    latestClient: fields['Latest Client (from Virtual Assistants)']?.[0] || 'N/A',
    latestRole: fields['Latest Role (from Virtual Assistants)']?.[0] || 'N/A',
    skillsTools: formatSkillsTools(fields['Skills | Tools']),
    reasonForCancellation: fields['Reason for MVA Cancellation'] || 'N/A',
    memo: fields['Memo'] || 'N/A',
    lastDayWithClient: formatDate(fields['Last day with the client']),
    readyForInterviews: formatDate(fields['Ready for Interviews']),
    svEmail: fields['SV Email']?.[0] || fields['B2P Email']?.[0] || 'N/A',
    personalEmail: fields['Personal Email']?.[0] || 'N/A',
    resumeUrl,
    extractedResumeText: extractedText
  });
}

// ============================================
// BUILD HTML EMAIL FOR EACH VA (CLEAN VERSION)
// ============================================
const emailOutputs = vaRecords.map(va => {
  const htmlMessage = `
  <div style="font-family: Arial, sans-serif; color: #333; max-width: 800px; margin: 0 auto;">
    <p style="font-size: 14px; margin-bottom: 20px;">Hi Team,</p>

    <p style="font-size: 14px; margin-bottom: 20px;">
      See <strong>placement ready</strong> for VA <strong>${va.name}</strong>. Here's the 
      <a href="${va.resumeUrl || '#'}" style="color: #0066cc; text-decoration: underline;">link</a> to the updated CV.
    </p>

    <table border="1" cellpadding="10" cellspacing="0" style="border-collapse: collapse; width: 100%; font-size: 14px; border: 2px solid #6E86AD;">
      <thead>
        <tr style="background-color: #F17D19;">
          <th colspan="2" style="color: white; text-align: center; padding: 12px; font-size: 16px;">
            VA Endorsement to <strong>Placement</strong>
          </th>
        </tr>
      </thead>
      <tbody>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold; width: 30%;">Name</td>
          <td style="padding: 10px;">${va.name}</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold;">Previous Client</td>
          <td style="padding: 10px;">${va.latestClient}</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold;">Previous Role</td>
          <td style="padding: 10px;">${va.latestRole}</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold;">Tenure with Previous Client</td>
          <td style="padding: 10px;">See CV for details</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold; vertical-align: top;">Skills/Tools</td>
          <td style="padding: 10px; line-height: 1.6;">${va.skillsTools}</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold; vertical-align: top;">Reason for MVA Cancellation</td>
          <td style="padding: 10px;">${va.reasonForCancellation}</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold; vertical-align: top;">Memo</td>
          <td style="padding: 10px;">${va.memo}</td>
        </tr>
        <tr>
          <td style="background-color: #6E86AD; color: white; font-weight: bold;">Last day with the client</td>
          <td style="padding: 10px;">${va.lastDayWithClient}</td>
        </tr>
      </tbody>
    </table>

    <p style="font-size: 12px; color: #666; margin-top: 20px; font-style: italic;">
      This notification was automatically generated by the placement ready notification flow.
    </p>
  </div>
  `;

  return {
    json: {
      vaName: va.name,
      btpId: va.btpId,
      svEmail: va.svEmail,
      personalEmail: va.personalEmail,
      htmlMessage,
      subject: `Placement Ready - ${va.name}`,
      readyDate: va.readyForInterviews,
      extractedResumeText: va.extractedResumeText
    }
  };
});

// ============================================
// OUTPUT RESULTS
// ============================================
return emailOutputs;
